def main(request):
    """HTTP Cloud Function.
        - This cloud function will be automatically invoked in the 
        deployment pipeline to load the environemnt variables into firestore.
        Or users can manually call the function to update the system.

        GET - with no arguments will return the current configuration
        https://..../initial_firestore_config
        response:
        {
            "embedding_model": "text-embedding-ada-002",
            ...etc.
        }

        GET
        https://..../initial_firestore_config?embedding_model=text-embedding-ada-002
        response: function variables json

        POST
        https://..../initial_firestore_config
        the environment input json file is located in the terraform/vars/{env}/env_config.json
        the other collection json is stored in the 'collections' variable, 
        need to the update the 'collections' variable for changes

        For automately running:
            the function will read the variables in the terraform/vars/{env}/env_config.json
            and add the json into the 'collections' variable, and update all the collections
        For manually inserting:
            The function will read the input json (must contain in the 'collections' key),
            and update only the variables contained in the input json
        response: function variables json
    """

    func_config = gcp_get_config()
    logger = gcp_logger()
    db = firestore.Client()

    if request.method == 'GET':
        if len(request.args) > 0:
            for key in request.args:
                if key != 'key':
                    func_config[key] = request.args[key]
        db.collection('function_configuration').document('project_variables').set(func_config)
        logger.debug(f"The configuration variables are {func_config}")

    elif request.method == 'POST':
        incoming_conf = request.get_json()
        input_collections = incoming_conf.get("collections", [])
        # check if it is valid inputs
        if not input_collections:
            collection_name = incoming_conf.get("collection_name", "")
            collection_json = incoming_conf.get("documents", [])
            # check if it is automatically inserting
            if not collection_json:
                logger.debug("No input configurations, exit.")
                return "Wrong input", 201
            if collection_name != "function_configuration":
                logger.debug("No input configurations, exit.")
                return "Wrong input", 201
            else:
                # if it is automatically inserting, all the collections are updated
                collections.append(incoming_conf)
                logger.debug("automatically inserting configurations into firestore...")
                load_return = load_collections(db, collections)

        else:
            # if it is manually inserting, only the input collections are updated
            logger.debug("manually inserting configurations into firestore...")
            load_return = load_collections(db, input_collections)
        if not load_return:
            logger.debug(f"Empty json found in the collections: {input_collections}")
            return "Empty input", 201

    return json.dumps(func_config, indent=4), 200

def load_collections(db, input_collections):
    for collection in input_collections:
        collection_name = collection.get("collection_name", "")
        if not collection_name:
            return ""
        else:
            for document in collection.get("documents", []):
                document_name = document.get("document_name", "")
                document_json = document.get("document_json", {})
                if not document_json:
                    return ""
                db.collection(collection_name).document(document_name).set(document_json)
    return "ok"
